        val user = QUserEntity.userEntity
        val profile = QProfileEntity.profileEntity

        return queryFactory
            .select(
                Projections.constructor(
                    MatchingCandidateDto::class.java,
                    user.id,
                    profile.nickname,
                    profile.gender,
                    profile.age,
                    profile.profileImageUrl,
                    profile.voiceIntroUrl,
                )
            )
            .from(user)
            .innerJoin(profile).on(profile.userId.eq(user.id))
            .where(
                user.status.eq("ACTIVE"),
                user.id.notIn(excludeIds),           // 블락/이미 매칭된 유저 한번에 제외
                user.id.ne(requesterId),
            )
            .limit(limit.toLong())
            .fetch()
    }
}
```

